INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('policepromo-8b7f1efc-moex-00019', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '依政府資訊公開法，有關政府資訊應否公開之敘述，下列何者錯誤？', '["政府機關以預算補助特定企業之補助金等相關資訊，應主動公開", "牽涉國防預算之資訊，如經依法核定為國家機密者，得不主動公開", "屬於書面之公共工程及採購契約者，如：臺北大巨蛋，應主動公開", "合議制機關之會議紀錄，如：內政部都市計畫委員會，應主動公開"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 15, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00020', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '甲因貪圖免費享用壽司，配合店家宣傳廣告而改名為有魚部首之名字。當甲後悔欲申請改名時，主管機關 認為其符合姓名條例第9條第1項第6款之特殊原因，得申請改名。前開規定中所稱之「特殊原因」，係 屬於下列何種行政法之概念？', '["判斷餘地", "裁量餘地", "裁量基準", "不確定法律概念"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00021', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '有關行政處分與行政契約之比較，下列敘述何者正確？', '["基於契約之相對性，行政契約無從產生對第三人之拘束效力", "信賴保護原則之適用對象範圍，包括行政處分與行政契約之相對人", "具有對第三人效力之行政處分，其效力之發生繫於第三人之事前同意", "行政契約或行政處分，其對第三人效力之有無，均以法規有明定為前提"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00022', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '行政機關於颱風侵襲期間，為避免緊急危險，引水進入尚未完工之分洪隧道，應屬於下列何種概念之行政 措施？', '["定暫時狀態之假處分", "維護人民生命財產之保全處分", "防止損害擴大之暫時性行政處分", "行政執行法上之即時強制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00023', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列何者為具有法效性之單方行政行為？', '["具對第三人效力之行政處分", "具間接對外效力之行政指導", "不須第三人同意之行政契約", "具可代替性之行政事實行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00024', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '有關行政罰之敘述，下列何者正確？', '["裁罰性之不利處分，亦包括強制拆除", "警告性處分只是單純警告，並不屬於行政罰", "行為後法律有變更者，適用最初行為時之法律", "公布違法者之姓名，影響其權益輕微，無須適用法律保留原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00025', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '關於行政契約，下列敘述何者正確？', '["因行政契約之性質屬於公法契約，故不得準用民法之相關規定", "契約締結後如有情事重大變更，當事人之一方得依法終止契約", "準用民法規定之結果雖為無效，但依行政程序法並不當然無效", "如無自願接受執行約定，得準用民事訴訟法有關強制執行規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00026', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '有關行政契約與行政法一般原則之敘述，下列何者正確？', '["公法上法律關係得以行政契約設定、變更或消滅之，並不適用法律優位原則", "基於私法自治原則之授權，公法上法律關係得以行政契約設定、變更或消滅之", "依其性質或法規規定雖不得締結行政契約，但該契約約款仍應適用比例原則", "以甄選方式決定當事人，應事先公告應具之資格，係落實正當法律程序原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00027', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '依行政程序法之規定，有關人民向行政機關提出之陳情，下列敘述何者正確？', '["行政機關對人民之陳情，應訂定作業規定，組成陳情處理委員會迅速、確實回應", "以言詞為陳情者，受理機關得不作成紀錄，即時處理並作成暫時性保全行政處分", "陳情之事項，屬於得提起訴願、訴訟或請求國家賠償者，陳情人仍得依法提起之", "人民之陳情雖有保密之必要，但受理機關處理時，得依據職權基於公益予以公開"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00028', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '關於法規命令與行政規則之比較，下列敘述何者正確？', '["均得依職權舉行聽證訂定", "均須先於政府公報發布之", "均得依人民之提議訂定之", "均得為行政法之成文法源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL)
